// ==============================================
// EXTRAI dados essenciais da mensagem recebida
// ==============================================
const payload = $input.first().json;

// Pega o telefone sem @c.us (ex: 5548999999999)
const telefone = (payload.payload?.from || payload.from || '')
  .replace('@c.us', '')
  .replace('@lid', '');

// Texto da mensagem (minúsculo para comparações)
const texto = (
  payload.payload?.body ||
  payload.payload?.text ||
  payload.body ||
  ''
).trim();

const textoLower = texto.toLowerCase();

// Nome do contato (se disponível)
const nome = payload.payload?.notifyName ||
             payload._data?.notifyName ||
             'Lead';

// ID único da mensagem
const messageId = payload.id || payload.payload?.id || '';

// Ignora mensagens próprias (enviadas pelo bot)
if (payload.payload?.fromMe === true || payload.fromMe === true) {
  return [{ json: { ignorar: true } }];
}

return [{
  json: {
    telefone,
    texto,
    textoLower,
    nome,
    messageId,
    ignorar: false
  }
}];

// ==============================================
// DETERMINA o estado atual do lead
// Se não existe na planilha = lead NOVO
// ==============================================
const dadosMensagem = $('⚙️ Extrai Dados da Mensagem').item.json;
const resultadoSheets = $input.first().json;

// Se não achou na planilha, é lead novo
const leadExiste = resultadoSheets.telefone !== undefined;

const status = leadExiste
  ? (resultadoSheets.status || 'NOVO')
  : 'NOVO';

const nomeConhecido = leadExiste
  ? (resultadoSheets.nome || dadosMensagem.nome)
  : dadosMensagem.nome;

return [{
  json: {
    ...dadosMensagem,
    status,
    nomeConhecido,
    leadExiste,
    interesse: resultadoSheets.interesse || '',
    disponibilidade: resultadoSheets.disponibilidade || ''
  }
}];
